const d = $input.first().json;
const wfs = d._workflows || [];
const dls = d._dead_letters || [];
const appr = d._approvals || [];
let total_execs = 0;
let total_failed = 0;
let core_failed = false;
for (const w of wfs) {
  total_execs += w.executions_total || 0;
  total_failed += w.executions_failed || 0;
  if (w.name && w.name.startsWith("CORE -") && (w.executions_failed > 0 || w.success_rate < 95)) {
    core_failed = true;
  }
}
const success_rate = total_execs > 0 ? parseFloat(((total_execs - total_failed) / total_execs * 100).toFixed(2)) : 100;
const critical_dead = dls.filter(dl => dl.severity === "critical" && dl.status === "waiting_review").length;
const critical_appr = appr.filter(a => a.severity === "critical" && a.status === "pending").length;
let overall = "healthy";
if (success_rate < 80 || core_failed || critical_dead > 0 || !d.portal_synced) {
  overall = "critical";
} else if (success_rate < 95 || dls.length > 2 || critical_appr > 0) {
  overall = "degraded";
}
const recs = [];
if (overall === "critical") {
  recs.push("Atenção Imediata: Corrigir falhas críticas nos agentes principais.");
  if (core_failed) recs.push("Revisar logs do CORE - Gateway Supervisor ou Approval Center.");
  if (critical_dead > 0) recs.push("Revisar Dead Letters de severidade crítica.");
  if (!d.portal_synced) recs.push("Restabelecer conexão com a API do Portal Vesper.");
} else if (overall === "degraded") {
  recs.push("Monitorar: Taxa de sucesso geral abaixo de 95% ou acúmulo de dead letters.");
  if (critical_appr > 0) recs.push("Aprovar validações pendentes penduradas.");
} else {
  recs.push("Todos os sistemas estão operando dentro dos parâmetros normais.");
}
d.status = "success";
d.data = {
  health: {
    overall_status: overall,
    overall_success_rate: success_rate,
    total_executions: total_execs,
    total_failed: total_failed,
    portal_synced: d.portal_synced,
    recommends: recs
  }
};
d.risk_level = overall === "critical" ? "critical" : (overall === "degraded" ? "high" : "low");
return [{json: d}];

