  "- Custo IA estimado hoje: USD " + (costs.estimated_ai_cost_today || 0) + "\n\n" +
  "Recomendações:\n";
if (total_dl > 0) {
  summary_text += "- Resolver as " + total_dl + " Dead Letters pendentes.\n";
}
if (pending_appr > 0) {
  summary_text += "- Há " + pending_appr + " aprovações aguardando ação no Approval Center.\n";
}
if (total_dl === 0 && pending_appr === 0) {
  summary_text += "- Nenhuma ação crítica pendente de atenção.\n";
}
d.status = "daily_summary_ready";
d.summary = summary_text;
d.data = {
