  daily_summary_text: summary_text
};
d.risk_level = "low";
return [{json: d}];

const d = $input.first().json;
const wfs = d._workflows || [];
const dls = d._dead_letters || [];
const error_wfs = wfs.filter(w => w.executions_failed > 0);
const total_errors = error_wfs.reduce((acc, curr) => acc + curr.executions_failed, 0);
const by_severity = { critical: 0, high: 0, medium: 0, low: 0 };
for (const dl of dls) {
  if (dl.severity in by_severity) {
    by_severity[dl.severity]++;
  }
}
d.status = "success";
d.data = {
  errors: {
    total_errors: total_errors,
    by_severity: by_severity,
    affected_workflows: error_wfs.map(w => ({ name: w.name, failed: w.executions_failed })),
    last_error_at: new Date().toISOString()
  }
};
d.risk_level = by_severity.critical > 0 ? "critical" : (by_severity.high > 0 ? "high" : "medium");
return [{json: d}];

