    critical_pending: critical_pending,
    by_type: by_type,
    approved_today: 5,
    rejected_today: 1
  }
};
d.next_action = critical_pending > 0 ? "review_critical_approvals" : "";
d.risk_level = critical_pending > 0 ? "critical" : (pending > 0 ? "high" : "low");
return [{json: d}];

const d = $input.first().json;
const dls = d._dead_letters || [];
const open = dls.filter(dl => dl.status === "waiting_review").length;
const retry = dls.filter(dl => dl.status === "retry_scheduled").length;
const critical = dls.filter(dl => dl.severity === "critical" && dl.status === "waiting_review").length;
const recs = [];
if (critical > 0) recs.push("Revisar erro crítico repetitivo no Portal ou credenciais.");
if (open > 0) recs.push("Realizar auditoria manual de payloads pendentes.");
d.status = "success";
d.data = {
  dead_letters: {
    open_dead_letters: open,
    retry_pending: retry,
    critical_dead_letters: critical,
    recommendations: recs
  }
};
d.risk_level = critical > 0 ? "critical" : (open > 0 ? "high" : "medium");
return [{json: d}];

const d = $input.first().json;
const wfs = d._workflows || [];
const agents_list = [
  { agent: "core", workflows: ["CORE - Error Audit Dead Letter", "CORE - Approval Center", "CORE - Gateway Supervisor"] },
  { agent: "compras", workflows: ["COMPRAS - Procure to Pay Agent"] },
  { agent: "comercial", workflows: ["COMERCIAL - Quote to Cash Agent"] },
  { agent: "producao", workflows: ["PRODUCAO - Kanban OP Agent"] },
  { agent: "interno", workflows: ["INTERNO - Portal Assistant"] },
  { agent: "knowledge", workflows: ["KNOWLEDGE - RAG Auditoria"] },
  { agent: "war_room", workflows: ["WAR ROOM - Observability"] }
];
const consolidated = agents_list.map(a => {
  let total_runs = 0;
  let total_fails = 0;
  let active = true;
  for (const name of a.workflows) {
    const wf = wfs.find(w => w.name === name);
    if (wf) {
      total_runs += wf.executions_total || 0;
      total_fails += wf.executions_failed || 0;
      if (!wf.active) active = false;
    }
  }
  const rate = total_runs > 0 ? parseFloat(((total_runs - total_fails) / total_runs * 100).toFixed(2)) : 100;
  return {
    agent: a.agent,
    status: active ? (rate >= 95 ? "healthy" : (rate >= 80 ? "degraded" : "critical")) : "inactive",
    success_rate: rate,
    last_seen: new Date().toISOString()
  };
});
d.status = "success";
d.data = {
  agents: consolidated
};
d.risk_level = consolidated.some(a => a.status === "critical") ? "critical" : "low";
return [{json: d}];

const d = $input.first().json;
const costs = d._costs || {};
d.status = "success";
d.data = {
  costs: costs
};
d.risk_level = costs.estimated_ai_cost_today > 15 ? "medium" : "low";
return [{json: d}];

const d = $input.first().json;
const logs = d._audit_logs || [];
