const d = $input.first().json;
const wfs = d._workflows || [];
const dls = d._dead_letters || [];
const appr = d._approvals || [];
const alerts = [];
if (!d.portal_synced) {
  alerts.push({
    alert_id: "alt_portal_down",
    severity: "critical",
    title: "Portal API Indisponivel",
    message: "Nao foi possivel sincronizar dados com o Portal Vesper.",
    agent: "war_room",
    created_at: new Date().toISOString(),
    next_action: "check_portal_network"
  });
}
for (const w of wfs) {
  if (w.name.startsWith("CORE -") && w.executions_failed > 0) {
    alerts.push({
      alert_id: "alt_core_fail_" + w.id,
      severity: "critical",
      title: "Falha em Workflow Core",
      message: "O workflow " + w.name + " registrou falhas recentes.",
      agent: "core",
      workflow: w.name,
      created_at: new Date().toISOString(),
      next_action: "audit_core_logs"
    });
  }
}
for (const dl of dls) {
  if (dl.severity === "critical") {
    alerts.push({
      alert_id: "alt_dl_" + dl.id,
      severity: "critical",
      title: "Dead Letter Critica",
      message: "Dead letter critica aberta: " + dl.error_message,
      agent: dl.workflow_name.split(" ")[0].toLowerCase(),
      workflow: dl.workflow_name,
      created_at: dl.created_at,
      next_action: "manual_review"
    });
  }
}
for (const a of appr) {
  if (a.severity === "critical" && a.status === "pending") {
    alerts.push({
      alert_id: "alt_appr_" + a.id,
      severity: "critical",
      title: "Aprovacao Critica Pendente",
      message: "Validacao critica pendente: " + a.title,
      agent: "core",
      created_at: a.created_at,
      next_action: "review_critical_approvals"
    });
  }
}
d.status = alerts.length > 0 ? "alerts_found" : "no_alerts";
d.data = {
  alerts: alerts
};
d.risk_level = alerts.some(a => a.severity === "critical") ? "critical" : "low";
return [{json: d}];

const d = $input.first().json;
const wfs = d._workflows || [];
const dls = d._dead_letters || [];
