const raw = $input.first().json;
const d = raw.body || raw.query || raw;
d.runtime_mode = (d.runtime_mode || "MOCK").toUpperCase();
d.correlation_id = d.correlation_id || ("WRM-" + Date.now());
d.request_id = d.request_id || ("REQ-" + Math.random().toString(36).substr(2,8).toUpperCase());
d.source = d.source || "manual";
d.user = d.user || { id: "", name: "", role: "", department: "" };
d.payload = d.payload || {};
d.metadata = d.metadata || {};
const msg = (d.message || "").toLowerCase();
const action = d.action || "";
if (!action) {
  if (/erro|falha|dead letter|deadletter/.test(msg)) {
    if (/dead/.test(msg)) {
      d.action = "dead_letters_summary";
    } else {
      d.action = "errors_summary";
    }
  } else if (/aprov/.test(msg)) {
    d.action = "approvals_summary";
  } else if (/custo|credito|crédito|token|preco|preço/.test(msg)) {
    d.action = "cost_summary";
  } else if (/resumo|daily/.test(msg)) {
    d.action = "daily_summary";
  } else if (/status|agente|workflow/.test(msg)) {
    d.action = "agent_status";
  } else if (/snapshot|snap/.test(msg)) {
    d.action = "snapshot";
  } else if (/alerta|critico|crítico/.test(msg)) {
    d.action = "critical_alerts";
  } else if (/auditoria|eventos/.test(msg)) {
    d.action = "audit_summary";
  } else {
    d.action = "health_check";
  }
}
return [{json: d}];

